import{_ as e,o as i,c as l,ae as s}from"./chunks/framework.BEtfQoF7.js";const u=JSON.parse('{"title":"체크포인팅","description":"Claude의 편집과 대화를 추적, 되감기, 요약하여 세션 상태를 관리합니다.","frontmatter":{"title":"체크포인팅","description":"Claude의 편집과 대화를 추적, 되감기, 요약하여 세션 상태를 관리합니다."},"headers":[],"relativePath":"checkpointing.md","filePath":"checkpointing.md","lastUpdated":1776155129000}'),t={name:"checkpointing.md"};function o(n,a,r,d,h,c){return i(),l("div",null,[...a[0]||(a[0]=[s(`<h1 id="체크포인팅" tabindex="-1">체크포인팅 <a class="header-anchor" href="#체크포인팅" aria-label="Permalink to &quot;체크포인팅&quot;">​</a></h1><p>Claude Code는 작업 중 Claude의 파일 편집을 자동으로 추적하여, 문제가 발생했을 때 빠르게 변경 사항을 취소하고 이전 상태로 되돌릴 수 있습니다.</p><h2 id="체크포인트-작동-방식" tabindex="-1">체크포인트 작동 방식 <a class="header-anchor" href="#체크포인트-작동-방식" aria-label="Permalink to &quot;체크포인트 작동 방식&quot;">​</a></h2><p>Claude와 작업하는 동안 체크포인팅은 각 편집 전에 코드 상태를 자동으로 캡처합니다. 이 안전망 덕분에 언제든지 이전 코드 상태로 돌아갈 수 있다는 확신을 가지고 대규모 작업을 진행할 수 있습니다.</p><h3 id="자동-추적" tabindex="-1">자동 추적 <a class="header-anchor" href="#자동-추적" aria-label="Permalink to &quot;자동 추적&quot;">​</a></h3><p>Claude Code는 파일 편집 도구로 수행된 모든 변경 사항을 추적합니다:</p><ul><li>모든 사용자 프롬프트가 새로운 체크포인트를 생성합니다</li><li>체크포인트는 세션 간에 유지되므로 재개된 대화에서도 접근할 수 있습니다</li><li>세션과 함께 30일 후 자동으로 정리됩니다 (설정 가능)</li></ul><h3 id="되감기와-요약" tabindex="-1">되감기와 요약 <a class="header-anchor" href="#되감기와-요약" aria-label="Permalink to &quot;되감기와 요약&quot;">​</a></h3><p><code>Esc</code>를 두 번 누르거나 (<code>Esc</code> + <code>Esc</code>) <code>/rewind</code> 명령을 사용하여 되감기 메뉴를 엽니다. 스크롤 가능한 목록에 세션의 각 프롬프트가 표시됩니다. 작업할 지점을 선택한 다음 동작을 선택합니다:</p><ul><li><strong>코드와 대화 복원</strong>: 해당 지점으로 코드와 대화를 모두 되돌립니다</li><li><strong>대화 복원</strong>: 현재 코드를 유지하면서 해당 메시지로 되돌립니다</li><li><strong>코드 복원</strong>: 대화를 유지하면서 파일 변경 사항을 되돌립니다</li><li><strong>여기서부터 요약</strong>: 이 지점 이후의 대화를 요약으로 압축하여 컨텍스트 윈도우 공간을 확보합니다</li><li><strong>취소</strong>: 변경 없이 메시지 목록으로 돌아갑니다</li></ul><p>대화 복원 또는 요약 후, 선택한 메시지의 원래 프롬프트가 입력 필드에 복원되어 다시 전송하거나 편집할 수 있습니다.</p><h4 id="복원-vs-요약" tabindex="-1">복원 vs. 요약 <a class="header-anchor" href="#복원-vs-요약" aria-label="Permalink to &quot;복원 vs. 요약&quot;">​</a></h4><p>세 가지 복원 옵션은 상태를 되돌립니다: 코드 변경, 대화 기록 또는 둘 다를 취소합니다. &quot;여기서부터 요약&quot;은 다르게 작동합니다:</p><ul><li>선택한 메시지 이전의 메시지는 그대로 유지됩니다</li><li>선택한 메시지와 이후의 모든 메시지가 AI가 생성한 간결한 요약으로 대체됩니다</li><li>디스크의 파일은 변경되지 않습니다</li><li>원본 메시지는 세션 트랜스크립트에 보존되므로 Claude가 필요할 때 세부 사항을 참조할 수 있습니다</li></ul><p>이는 <code>/compact</code>와 유사하지만 더 타겟팅된 방식입니다: 전체 대화를 요약하는 대신 초기 컨텍스트는 전체 세부 사항을 유지하고 공간을 차지하는 부분만 압축합니다. 요약이 집중할 내용을 안내하는 선택적 지시사항을 입력할 수 있습니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>요약은 동일한 세션에 머물면서 컨텍스트를 압축합니다. 원래 세션을 그대로 유지하면서 다른 접근 방식을 시도하려면 <a href="/claude-code-docs-ko/how-claude-code-works.html#resume-or-fork-sessions">포크</a>를 사용하세요 (<code>claude --continue --fork-session</code>).</p></div><h2 id="일반적인-사용-사례" tabindex="-1">일반적인 사용 사례 <a class="header-anchor" href="#일반적인-사용-사례" aria-label="Permalink to &quot;일반적인 사용 사례&quot;">​</a></h2><p>체크포인트는 다음과 같은 경우에 특히 유용합니다:</p><ul><li><strong>대안 탐색</strong>: 시작점을 잃지 않고 다양한 구현 접근 방식을 시도합니다</li><li><strong>실수 복구</strong>: 버그를 도입하거나 기능을 손상시킨 변경 사항을 빠르게 취소합니다</li><li><strong>기능 반복</strong>: 작동하는 상태로 되돌릴 수 있다는 확신을 가지고 변형을 실험합니다</li><li><strong>컨텍스트 공간 확보</strong>: 초기 지시사항은 그대로 유지하면서 중간 지점부터 장황한 디버깅 세션을 요약합니다</li></ul><h2 id="제한-사항" tabindex="-1">제한 사항 <a class="header-anchor" href="#제한-사항" aria-label="Permalink to &quot;제한 사항&quot;">​</a></h2><h3 id="bash-명령-변경은-추적되지-않음" tabindex="-1">Bash 명령 변경은 추적되지 않음 <a class="header-anchor" href="#bash-명령-변경은-추적되지-않음" aria-label="Permalink to &quot;Bash 명령 변경은 추적되지 않음&quot;">​</a></h3><p>체크포인팅은 bash 명령으로 수정된 파일을 추적하지 않습니다. 예를 들어, Claude Code가 다음을 실행하면:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> old.txt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> source.txt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dest.txt</span></span></code></pre></div><p>이러한 파일 수정은 되감기를 통해 취소할 수 없습니다. Claude의 파일 편집 도구를 통해 직접 수행된 편집만 추적됩니다.</p><h3 id="외부-변경은-추적되지-않음" tabindex="-1">외부 변경은 추적되지 않음 <a class="header-anchor" href="#외부-변경은-추적되지-않음" aria-label="Permalink to &quot;외부 변경은 추적되지 않음&quot;">​</a></h3><p>체크포인팅은 현재 세션에서 편집된 파일만 추적합니다. Claude Code 외부에서 수동으로 수행한 변경과 다른 동시 세션의 편집은 현재 세션과 동일한 파일을 수정하지 않는 한 일반적으로 캡처되지 않습니다.</p><h3 id="버전-관리를-대체하지-않음" tabindex="-1">버전 관리를 대체하지 않음 <a class="header-anchor" href="#버전-관리를-대체하지-않음" aria-label="Permalink to &quot;버전 관리를 대체하지 않음&quot;">​</a></h3><p>체크포인트는 빠른 세션 수준 복구를 위해 설계되었습니다. 영구적인 버전 이력과 협업을 위해:</p><ul><li>커밋, 브랜치 및 장기 이력을 위해 버전 관리(예: Git)를 계속 사용하세요</li><li>체크포인트는 적절한 버전 관리를 보완하지만 대체하지는 않습니다</li><li>체크포인트는 &quot;로컬 실행 취소&quot;, Git은 &quot;영구 이력&quot;으로 생각하세요</li></ul><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li><a href="/claude-code-docs-ko/interactive-mode.html">인터랙티브 모드</a> - 키보드 단축키 및 세션 제어</li><li><a href="/claude-code-docs-ko/commands.html">명령어</a> - <code>/rewind</code>를 사용한 체크포인트 접근</li><li><a href="/claude-code-docs-ko/cli-reference.html">CLI 레퍼런스</a> - 명령줄 옵션</li></ul>`,31)])])}const k=e(t,[["render",o]]);export{u as __pageData,k as default};
